function decodeBase64ToUint8Array(base64) {
  const chars =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
  const lookup = Object.create(null);
  for (let i = 0; i < chars.length; i += 1) {
    lookup[chars[i]] = i;
  }

  const cleaned = base64.replace(/\s+/g, "");
  const padding = cleaned.endsWith("==") ? 2 : cleaned.endsWith("=") ? 1 : 0;
  const outLen = (cleaned.length * 3) / 4 - padding;
  const out = new Uint8Array(outLen);

  let outIndex = 0;
  for (let i = 0; i < cleaned.length; i += 4) {
    const c1 = lookup[cleaned[i]];
    const c2 = lookup[cleaned[i + 1]];
    const c3 = cleaned[i + 2] === "=" ? 0 : lookup[cleaned[i + 2]];
    const c4 = cleaned[i + 3] === "=" ? 0 : lookup[cleaned[i + 3]];

    const chunk = (c1 << 18) | (c2 << 12) | (c3 << 6) | c4;
    out[outIndex++] = (chunk >> 16) & 0xff;
    if (cleaned[i + 2] !== "=") {
      out[outIndex++] = (chunk >> 8) & 0xff;
    }
    if (cleaned[i + 3] !== "=") {
      out[outIndex++] = chunk & 0xff;
    }
  }

  return out;
}

if ($request.url !== TARGET_URL) {
  $done({});
} else {
  const body = decodeBase64ToUint8Array(BASE64_CHUNKS.join(""));
  $done({
    status: 200,
    headers: {
      "content-type": "application/octet-stream",
      "cache-control": "no-store",
    },
    body,
  });
}
